import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(pos1, pos2):
        return np.linalg.norm(pos1 - pos2) / truck_speed

    best_node = None
    min_cost = float('inf')

    for idx, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[idx]

        if start_window > arrival_time:
            wait_time = start_window - arrival_time
        else:
            wait_time = 0

        if end_window < arrival_time:
            penalty = (arrival_time - end_window) * 10  # High penalty for missing time window
        else:
            penalty = 0

        cost = travel_time + wait_time + penalty
        if cost < min_cost:
            min_cost = cost
            best_node = idx

    # Return index of best unvisited customer to visit next
    return best_node
